import{_ as t,o as s,c as e,ag as l}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"공식 스킬 체험","description":"","frontmatter":{},"headers":[],"relativePath":"학습자료/2-스킬개념/2-2-공식스킬체험.md","filePath":"학습자료/2-스킬개념/2-2-공식스킬체험.md"}'),i={name:"학습자료/2-스킬개념/2-2-공식스킬체험.md"};function o(n,a,d,p,c,r){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="공식-스킬-체험" tabindex="-1">공식 스킬 체험 <a class="header-anchor" href="#공식-스킬-체험" aria-label="Permalink to &quot;공식 스킬 체험&quot;">​</a></h1><h2 id="이번-시간-목표" tabindex="-1">이번 시간 목표 <a class="header-anchor" href="#이번-시간-목표" aria-label="Permalink to &quot;이번 시간 목표&quot;">​</a></h2><p>직접 만들기 전에, <strong>남이 만든 스킬</strong>을 먼저 써봅니다.</p><ul><li>Anthropic 공식 스킬이 뭔지 안다</li><li>스킬을 설치하는 두 가지 방법을 익힌다</li><li><strong>slack-gif-creator로 GIF를 직접 만들어본다</strong></li><li>&quot;스킬 하나로 이런 것까지 되는구나!&quot; 를 체감한다</li></ul><hr><h2 id="공식-스킬이란" tabindex="-1">공식 스킬이란? <a class="header-anchor" href="#공식-스킬이란" aria-label="Permalink to &quot;공식 스킬이란?&quot;">​</a></h2><p>Claude를 만든 <strong>Anthropic</strong>이 직접 만들어서 GitHub에 공개한 스킬입니다. 누구나 무료로 다운받아 쓸 수 있어요.</p><div class="info custom-block"><p class="custom-block-title">공식 스킬 저장소</p><p>Anthropic의 GitHub에서 다양한 공식 스킬을 확인할 수 있습니다. 문서 처리, 디자인, 업무 자동화 등 카테고리별로 정리되어 있어요.</p></div><h3 id="추천-스킬-카테고리" tabindex="-1">추천 스킬 카테고리 <a class="header-anchor" href="#추천-스킬-카테고리" aria-label="Permalink to &quot;추천 스킬 카테고리&quot;">​</a></h3><table tabindex="0"><thead><tr><th>카테고리</th><th>대표 스킬</th><th>하는 일</th><th style="text-align:center;">난이도</th></tr></thead><tbody><tr><td>문서 처리</td><td><code>pdf</code></td><td>PDF 읽기, 요약, 분석</td><td style="text-align:center;">쉬움</td></tr><tr><td>디자인</td><td><code>slack-gif-creator</code></td><td>Slack용 애니메이션 GIF 만들기</td><td style="text-align:center;">쉬움</td></tr><tr><td>업무</td><td><code>meeting-summary</code></td><td>회의록 자동 요약</td><td style="text-align:center;">쉬움</td></tr><tr><td>데이터</td><td><code>xlsx</code></td><td>엑셀 파일 읽기/분석</td><td style="text-align:center;">보통</td></tr><tr><td>프레젠테이션</td><td><code>pptx</code></td><td>PPT 파일 생성/수정</td><td style="text-align:center;">보통</td></tr></tbody></table><hr><h2 id="실습-1-수동-설치-폴더-이해용" tabindex="-1">실습 1: 수동 설치 (폴더 이해용) <a class="header-anchor" href="#실습-1-수동-설치-폴더-이해용" aria-label="Permalink to &quot;실습 1: 수동 설치 (폴더 이해용)&quot;">​</a></h2><p>스킬이 실제로 어떤 구조인지 이해하기 위해, 먼저 <strong>수동으로</strong> 설치해봅니다.</p><h3 id="step-1-github에서-스킬-다운로드" tabindex="-1">Step 1: GitHub에서 스킬 다운로드 <a class="header-anchor" href="#step-1-github에서-스킬-다운로드" aria-label="Permalink to &quot;Step 1: GitHub에서 스킬 다운로드&quot;">​</a></h3><ol><li>Anthropic 스킬 저장소 방문</li><li>원하는 스킬 폴더 찾기 (예: <code>slack-gif-creator/</code>)</li><li>폴더 안의 <code>SKILL.md</code> 파일 확인</li></ol><h3 id="step-2-내-스킬-폴더에-복사" tabindex="-1">Step 2: 내 스킬 폴더에 복사 <a class="header-anchor" href="#step-2-내-스킬-폴더에-복사" aria-label="Permalink to &quot;Step 2: 내 스킬 폴더에 복사&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>다운받은 스킬 폴더</span></span>
<span class="line"><span>      ↓ 복사</span></span>
<span class="line"><span>~/.claude/skills/slack-gif-creator/SKILL.md</span></span></code></pre></div><details class="details custom-block"><summary>Finder로 복사하는 방법 (Mac)</summary><ol><li>Finder 열기</li><li><code>Cmd + Shift + G</code> 누르기</li><li><code>~/.claude/skills/</code> 입력 후 이동</li><li>skills 폴더 안에 다운받은 스킬 폴더를 드래그</li><li>완료!</li></ol><p>skills 폴더가 없다면? Claude Code에게 &quot;~/.claude/skills/ 폴더 만들어줘&quot;라고 시키세요.</p></details><h3 id="step-3-설치-확인" tabindex="-1">Step 3: 설치 확인 <a class="header-anchor" href="#step-3-설치-확인" aria-label="Permalink to &quot;Step 3: 설치 확인&quot;">​</a></h3><p>Claude Code 채팅창에 입력:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용 가능한 스킬 목록을 보여줘</span></span></code></pre></div><p>방금 설치한 스킬이 목록에 보이면 성공!</p><hr><h2 id="더-쉬운-방법-명령어-한-줄" tabindex="-1">더 쉬운 방법: 명령어 한 줄 <a class="header-anchor" href="#더-쉬운-방법-명령어-한-줄" aria-label="Permalink to &quot;더 쉬운 방법: 명령어 한 줄&quot;">​</a></h2><p>수동 설치는 구조를 이해하기 위한 것이었고, 실제로는 <strong>명령어 한 줄</strong>이면 됩니다.</p><p>Claude Code 채팅창에:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>slack-gif-creator 스킬을 설치해줘</span></span></code></pre></div><p>또는 공식 스킬 마켓에서:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/install-skill slack-gif-creator</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">어떤 방법이든 결과는 같습니다</p><p>수동이든 명령어든, 결국 <code>~/.claude/skills/스킬이름/SKILL.md</code> 파일이 생기는 것은 동일합니다. 편한 방법을 쓰세요!</p></div><hr><h2 id="실습-2-slack-gif-creator로-gif-만들기" tabindex="-1">실습 2: slack-gif-creator로 GIF 만들기 <a class="header-anchor" href="#실습-2-slack-gif-creator로-gif-만들기" aria-label="Permalink to &quot;실습 2: slack-gif-creator로 GIF 만들기&quot;">​</a></h2><p>이제 오늘의 하이라이트입니다! <strong>스킬 하나로 애니메이션 GIF를 만들어봅시다.</strong></p><h3 id="왜-gif-스킬인가요" tabindex="-1">왜 GIF 스킬인가요? <a class="header-anchor" href="#왜-gif-스킬인가요" aria-label="Permalink to &quot;왜 GIF 스킬인가요?&quot;">​</a></h3><ul><li>눈에 보이는 결과물 → &quot;와, 스킬로 이런 것까지?&quot; 체감</li><li>Slack, 카톡, 이메일에 바로 활용 가능</li><li>만드는 과정이 재밌음!</li></ul><h3 id="step-1-스킬-설치-확인" tabindex="-1">Step 1: 스킬 설치 확인 <a class="header-anchor" href="#step-1-스킬-설치-확인" aria-label="Permalink to &quot;Step 1: 스킬 설치 확인&quot;">​</a></h3><p>아까 설치했다면 바로 사용 가능합니다. 확인해볼까요?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/slack-gif-creator 안녕하세요 텍스트가 반짝이는 GIF 만들어줘</span></span></code></pre></div><h3 id="step-2-다양한-gif-만들어보기" tabindex="-1">Step 2: 다양한 GIF 만들어보기 <a class="header-anchor" href="#step-2-다양한-gif-만들어보기" aria-label="Permalink to &quot;Step 2: 다양한 GIF 만들어보기&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">지금 해보세요! 아래 중 마음에 드는 걸 골라서 입력해보세요.</p></div><p><strong>예시 1: 축하 GIF</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/slack-gif-creator 🎉 축하합니다! 텍스트가 위에서 떨어지는 애니메이션 GIF</span></span></code></pre></div><p><strong>예시 2: 업무용 GIF</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/slack-gif-creator &quot;수고하셨습니다&quot; 라는 텍스트에 별이 반짝이는 GIF</span></span></code></pre></div><p><strong>예시 3: 자유 주제</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/slack-gif-creator [여러분이 원하는 내용을 자유롭게!]</span></span></code></pre></div><h3 id="step-3-결과물-확인" tabindex="-1">Step 3: 결과물 확인 <a class="header-anchor" href="#step-3-결과물-확인" aria-label="Permalink to &quot;Step 3: 결과물 확인&quot;">​</a></h3><p>GIF 파일이 생성되었나요? 파일을 열어서 확인해보세요.</p><div class="tip custom-block"><p class="custom-block-title">이걸 내 업무용으로도 만들 수 있다!</p><p>지금은 재미로 GIF를 만들었지만, 같은 원리로:</p><ul><li>매주 보내는 주간보고를 자동화하거나</li><li>고객 응대 이메일을 템플릿화하거나</li><li>회의록을 자동으로 정리하는 스킬도 만들 수 있습니다</li></ul><p><strong>스킬의 핵심은 &quot;SKILL.md 파일 하나&quot;라는 것, 기억하시죠?</strong></p></div><hr><h2 id="스킬-작동-원리-다이어그램" tabindex="-1">스킬 작동 원리 다이어그램 <a class="header-anchor" href="#스킬-작동-원리-다이어그램" aria-label="Permalink to &quot;스킬 작동 원리 다이어그램&quot;">​</a></h2><p>지금까지 해본 걸 정리하면 이런 흐름입니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 사용자: &quot;/slack-gif-creator 축하 GIF 만들어줘&quot;</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>② Claude Code: description 확인 → &quot;GIF 만들기 스킬이구나&quot;</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>③ SKILL.md 전문 읽기 → 출력 형식, 규칙, 도구 파악</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>④ 지침대로 GIF 생성 코드 작성 &amp; 실행</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>⑤ 결과: animated.gif 파일 생성!</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">핵심 포인트</p><p>모든 스킬은 이 흐름을 따릅니다. GIF든, 이메일이든, 보고서든 — 패턴은 동일합니다.</p><ol><li><strong>사용자가 요청</strong> → 2. <strong>description으로 스킬 매칭</strong> → 3. <strong>SKILL.md 읽기</strong> → 4. <strong>실행</strong> → 5. <strong>결과물</strong></li></ol></div><hr><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><table tabindex="0"><thead><tr><th>문제</th><th>원인</th><th>해결</th></tr></thead><tbody><tr><td>&quot;스킬을 찾을 수 없습니다&quot;</td><td>파일 위치가 잘못됨</td><td><code>~/.claude/skills/slack-gif-creator/SKILL.md</code> 경로 확인</td></tr><tr><td>스킬이 실행은 되는데 GIF가 안 만들어짐</td><td>의존성 부족</td><td>Claude Code에게 &quot;필요한 패키지 설치해줘&quot;라고 요청</td></tr><tr><td>GIF가 만들어졌는데 파일을 못 찾겠음</td><td>저장 경로 확인</td><td>Claude Code에게 &quot;방금 만든 GIF 파일 위치 알려줘&quot;라고 요청</td></tr><tr><td>아무 반응이 없음</td><td>Claude Code 재시작 필요</td><td>Claude Code를 껐다 다시 켜기</td></tr></tbody></table><hr><h2 id="완료-체크리스트" tabindex="-1">완료 체크리스트 <a class="header-anchor" href="#완료-체크리스트" aria-label="Permalink to &quot;완료 체크리스트&quot;">​</a></h2><ul><li>[ ] 공식 스킬이 뭔지 안다 (Anthropic이 공개한 SKILL.md)</li><li>[ ] 스킬 설치 방법 2가지를 안다 (수동 복사 / 명령어)</li><li>[ ] slack-gif-creator로 GIF를 직접 만들어봤다</li><li>[ ] 스킬 작동 흐름 5단계를 이해했다</li><li>[ ] &quot;이걸 내 업무에도 적용할 수 있겠다&quot;는 감이 온다</li></ul><hr><div class="info custom-block"><p class="custom-block-title">느끼셨나요?</p><p>남이 만든 스킬도 결국 <strong>SKILL.md 파일 하나</strong>입니다. 이제 직접 만들어볼 차례예요. 생각보다 쉽습니다!</p></div><p><strong><a href="/학습자료/2-스킬개념/2-3-첫스킬만들기">첫 스킬 만들기 →</a></strong></p>`,63)])])}const g=t(i,[["render",o]]);export{u as __pageData,g as default};
